/**
 * Monta payload OPIN-style para a seguradora de vida.
 *
 * Esquema esperado pelo mock:
 *   data: {
 *     contratante: { cep },
 *     segurado: { cpf, dataNascimento, sexo, fumante, profissao },
 *     beneficiarios: [ { nome, parentesco, percentual } ],
 *     cobertura: { capitalMorte, capitalInvalidezAcidente?, capitalInvalidezDoenca?,
 *                  capitalDoencasGraves?, auxilioFuneral?, diariaIncapacidade?, prazo }
 *   }
 */

const input = $('Gatilho').first().json;

const obrigatorios = ['cpf', 'data_nascimento', 'sexo', 'cep', 'beneficiarios', 'capital_morte'];
for (const campo of obrigatorios) {
  if (input[campo] === undefined || input[campo] === null || input[campo] === '') {
    throw new Error(`Campo obrigatório ausente: ${campo}`);
  }
}

const dataNasc = DateTime.fromISO(input.data_nascimento);
if (!dataNasc.isValid) {
  throw new Error('data_nascimento inválida. Esperado AAAA-MM-DD.');
}

const sexoNorm = String(input.sexo).toLowerCase().charAt(0);
if (!['m', 'f'].includes(sexoNorm)) {
  throw new Error('sexo inválido. Use "m" ou "f".');
}

let beneficiarios = input.beneficiarios;
if (typeof beneficiarios === 'string') {
  try { beneficiarios = JSON.parse(beneficiarios); } catch { throw new Error('beneficiarios deve ser JSON array.'); }
}
if (!Array.isArray(beneficiarios) || beneficiarios.length === 0) {
  throw new Error('beneficiarios deve ser uma lista com pelo menos 1 beneficiário.');
}
const totalPct = beneficiarios.reduce((s, b) => s + Number(b.percentual || 0), 0);
if (Math.abs(totalPct - 100) > 0.01) {
  throw new Error(`Percentuais dos beneficiários devem somar 100. Recebido: ${totalPct}`);
}

const capital = Number(input.capital_morte);
if (!Number.isFinite(capital) || capital < 10000) {
  throw new Error('capital_morte deve ser >= R$ 10.000.');
}

const idempotencyKey = input.idempotency_key || `task-${input.task_id}`;

const payload = {
  data: {
    contratante: {
      cep: String(input.cep).replace(/\D/g, '')
    },
    segurado: {
      cpf: String(input.cpf).replace(/\D/g, ''),
      dataNascimento: input.data_nascimento,
      sexo: sexoNorm,
      fumante: Boolean(input.fumante ?? false),
      profissao: input.profissao || 'outros'
    },
    beneficiarios: beneficiarios.map(b => ({
      nome: String(b.nome || '').trim(),
      parentesco: String(b.parentesco || 'outro').toLowerCase(),
      percentual: Number(b.percentual)
    })),
    cobertura: {
      capitalMorte: capital,
      capitalInvalidezAcidente: Number(input.capital_invalidez_acidente || 0),
      capitalInvalidezDoenca: Number(input.capital_invalidez_doenca || 0),
      capitalDoencasGraves: Number(input.capital_doencas_graves || 0),
      auxilioFuneral: Number(input.auxilio_funeral || 0),
      diariaIncapacidade: Number(input.diaria_incapacidade || 0),
      prazo: input.prazo || 'anualRenovavel'
    }
  }
};

return [{ json: { payload, idempotencyKey } }];

/**
 * Normaliza a resposta da seguradora e guarda o payload original
 * para o workflow de emissão poder reapresentar (validação stateless).
 */
const resposta = $input.first().json;

if (!resposta || !resposta.data) {
  throw new Error('Resposta inesperada da seguradora: ' + JSON.stringify(resposta).slice(0, 300));
}

const { consentId, planos, validadeDias } = resposta.data;

// Valor do card: média do prêmio anual entre as opções retornadas (estimativa de pipeline).
// Na emissão (WF 05) esse valor é substituído pelo prêmio anual efetivo do plano escolhido.
const valorEstimadoAnual = planos.length > 0
  ? Math.round(planos.reduce((sum, p) => sum + (p.premio?.anual || 0), 0) / planos.length)
  : 0;
const disclaimer = resposta.meta?.disclaimer;

const input = $('Gatilho').first().json;
const montarPayload = $('Montar payload').first().json;
const payloadOriginal = montarPayload.payload;
const idempotencyKey = montarPayload.idempotencyKey;

function formatBRL(v) { return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }); }

function labelCobertura(c) {
  const map = {
    morte: 'Morte',
    invalidez_permanente_acidente: 'Invalidez por acidente',
    invalidez_permanente_doenca: 'Invalidez por doença',
    doencas_graves: 'Doenças graves',
    auxilio_funeral: 'Auxílio funeral',
    diaria_incapacidade_temporaria: 'Diária de incapacidade'
  };
  const nome = map[c.tipo] ?? c.tipo;
  if (c.valorDiario !== undefined) return `  · ${nome}: ${formatBRL(c.valorDiario)}/dia`;
  return `  · ${nome}: ${formatBRL(c.capital)}`;
}

const resumoTexto = planos.map((p, i) => {
  const linhas = [
    `*Opção ${i + 1}: ${p.produto.nome}*`,
    `  Mensalidade: ${formatBRL(p.premio.mensal)}  ·  Anual: ${formatBRL(p.premio.anual)}`,
    `  Coberturas:`
  ];
  p.coberturas.forEach(c => linhas.push(labelCobertura(c)));
  linhas.push(`  Carência morte natural: ${p.carencias.morteNatural}`);
  return linhas.join('\n');
}).join('\n\n');

return [{
  json: {
    consentId,
    validadeDias,
    planos,
    disclaimer,
    resumo_texto: resumoTexto,
    task_id: input.task_id,
    account_id: input.account_id,
    board_id: input.board_id,
    idempotency_key: idempotencyKey,
    original_quote_request: payloadOriginal.data,
    valor_estimado_anual: valorEstimadoAnual
  }
}];
